import React from "react";
import { useParams, Link } from "react-router-dom";
import "../styles/News.css";

const articles = [
  {
    id: 1,
    title:
      "LENIENCY IN CRIMINAL SENTENCE FOR JUSTICE COLLABORATORS WHO SUPPORTS LAW ENFORCEMENT AUTHORITIES BY UNCOVERING CRIMINAL CASES",
    date: "06 February, 2025",
    image: "/images/justice.jpg",
    fullText:
      "This is the full article content. Explain everything here in detail...",
  },
  {
    id: 2,
    title:
      "PROTECTION OF OPEN-SOURCE SOFTWARE FROM A COPYRIGHT PERSPECTIVE IN INDONESIA",
    date: "06 February, 2025",
    image: "/images/open-source.jpg",
    fullText:
      "This is the full article content. Explain everything here in detail...",
  },
];

const NewsDetail = () => {
  const { id } = useParams();
  const article = articles.find((article) => article.id === parseInt(id));

  if (!article) {
    return <h2>Article not found</h2>;
  }

  return (
    <div className="NewsDetail">
      <h2>{article.title}</h2>
      <p className="news-date">📅 {article.date}</p>
      <img src={article.image} alt={article.title} className="news-detail-image" />
      <p>{article.fullText}</p>
      <Link to="/" className="back-button">
        ← Back to News
      </Link>
    </div>
  );
};

export default NewsDetail;
